document.addEventListener('DOMContentLoaded', () => {
    const mobileModeBtn = document.getElementById('openMobileModeBtn');
    if (!mobileModeBtn) return;

    function showMobileModeToast(message, type = 'success') {
        const currentToast = document.querySelector('.toast');
        if (currentToast) currentToast.remove();

        const toast = document.createElement('div');
        toast.className = 'toast ' + type;
        toast.textContent = message;
        document.body.appendChild(toast);

        requestAnimationFrame(() => toast.classList.add('show'));
        setTimeout(() => {
            toast.classList.remove('show');
            setTimeout(() => toast.remove(), 300);
        }, 1800);
    }

    mobileModeBtn.addEventListener('click', () => {
        mobileModeBtn.disabled = true;
        chrome.runtime.sendMessage({
            type: 'OPEN_MOBILE_MODE'
        }, response => {
            mobileModeBtn.disabled = false;

            if (chrome.runtime.lastError || !response?.success) {
                const error = response?.error === 'SEARCH_RUNNING' ? 'Đang chạy tìm kiếm, hãy dừng trước.' : 'Không mở được Mobile Mode.';
                showMobileModeToast('❌ ' + error, 'error');
                return;
            }

            document.querySelectorAll('[data-mode]').forEach(button => {
                button.classList.toggle('active', button.dataset.mode === 'mobile');
            });
            showMobileModeToast('📱 Đã mở Mobile Mode');
        });
    });
});

document.addEventListener('DOMContentLoaded', () => {
    const readToEarnBtn = document.getElementById('readToEarnBtn');
    if (!readToEarnBtn) return;
    const label = readToEarnBtn.querySelector('span');
    const defaultText = label ? label.textContent : 'Read to Earn';

    function showReadToEarnToast(message, type = 'success') {
        const currentToast = document.querySelector('.toast');
        if (currentToast) currentToast.remove();

        const toast = document.createElement('div');
        toast.className = 'toast ' + type;
        toast.textContent = message;
        document.body.appendChild(toast);

        requestAnimationFrame(() => toast.classList.add('show'));
        setTimeout(() => {
            toast.classList.remove('show');
            setTimeout(() => toast.remove(), 300);
        }, 2200);
    }

    function setReadToEarnStatus(state, notify = false) {
        if (!state) return;
        if (state.isRunning) {
            readToEarnBtn.disabled = true;
            if (label) {
                label.textContent = state.status === 'auth'
                    ? 'Dang lay token...'
                    : 'Read ' + state.currentArticle + '/' + state.totalArticles;
            }
            return;
        }

        readToEarnBtn.disabled = false;
        if (label) label.textContent = defaultText;

        if (!notify) return;

        if (state.status === 'done') {
            showReadToEarnToast('Read to Earn xong: +' + (state.totalGained || 0) + ' diem');
        } else if (state.status === 'error') {
            showReadToEarnToast('Read to Earn loi: ' + (state.error || 'unknown'), 'error');
        }
    }

    chrome.runtime.sendMessage({ type: 'GET_READ_TO_EARN_STATUS' }, response => {
        if (response?.success) setReadToEarnStatus(response.data);
    });

    chrome.runtime.onMessage.addListener(message => {
        if (message?.type === 'READ_TO_EARN_STATUS') {
            setReadToEarnStatus(message.data, true);
        } else if (message?.type === 'DAILY_CHECK_IN_STATUS' && message.data?.isRunning) {
            readToEarnBtn.disabled = true;
        }
    });

    readToEarnBtn.addEventListener('click', () => {
        readToEarnBtn.disabled = true;
        if (label) label.textContent = 'Dang bat dau...';

        chrome.runtime.sendMessage({ type: 'DO_READ_TO_EARN' }, response => {
            if (chrome.runtime.lastError || !response?.success) {
                const error = response?.error || chrome.runtime.lastError?.message || 'READ_TO_EARN_FAILED';
                readToEarnBtn.disabled = false;
                if (label) label.textContent = defaultText;

                const message = error === 'SEARCH_RUNNING'
                    ? 'Dang search, hay dung truoc.'
                    : error === 'READ_TO_EARN_RUNNING'
                        ? 'Read to Earn dang chay.'
                        : error === 'DAILY_CHECK_IN_RUNNING'
                            ? 'Check In dang chay.'
                            : 'Khong chay duoc Read to Earn: ' + error;
                showReadToEarnToast(message, 'error');
            }
        });
    });
});

document.addEventListener('DOMContentLoaded', () => {
    const checkInBtn = document.getElementById('checkInBtn');
    if (!checkInBtn) return;
    const label = checkInBtn.querySelector('span');
    const defaultText = label ? label.textContent : 'Check In';

    function showCheckInToast(message, type = 'success') {
        const currentToast = document.querySelector('.toast');
        if (currentToast) currentToast.remove();

        const toast = document.createElement('div');
        toast.className = 'toast ' + type;
        toast.textContent = message;
        document.body.appendChild(toast);

        requestAnimationFrame(() => toast.classList.add('show'));
        setTimeout(() => {
            toast.classList.remove('show');
            setTimeout(() => toast.remove(), 300);
        }, 2200);
    }

    function setCheckInStatus(state, notify = false) {
        if (!state) return;
        if (state.isRunning) {
            checkInBtn.disabled = true;
            if (label) {
                label.textContent = state.status === 'auth'
                    ? 'Dang lay token...'
                    : 'Check In type ' + (state.typeTried || '');
            }
            return;
        }

        checkInBtn.disabled = false;
        if (label) label.textContent = defaultText;

        if (!notify) return;

        if (state.status === 'done') {
            showCheckInToast('Check In xong: +' + (state.gainedPoints || 0) + ' diem');
        } else if (state.status === 'error') {
            showCheckInToast('Check In loi: ' + (state.error || 'unknown'), 'error');
        }
    }

    chrome.runtime.sendMessage({ type: 'GET_DAILY_CHECK_IN_STATUS' }, response => {
        if (response?.success) setCheckInStatus(response.data);
    });

    chrome.runtime.onMessage.addListener(message => {
        if (message?.type === 'DAILY_CHECK_IN_STATUS') {
            setCheckInStatus(message.data, true);
        } else if (message?.type === 'READ_TO_EARN_STATUS' && message.data?.isRunning) {
            checkInBtn.disabled = true;
        } else if (message?.type === 'STATUS_UPDATE' && message.data?.isRunning) {
            checkInBtn.disabled = true;
        }
    });

    checkInBtn.addEventListener('click', () => {
        checkInBtn.disabled = true;
        if (label) label.textContent = 'Dang bat dau...';

        chrome.runtime.sendMessage({ type: 'DO_DAILY_CHECK_IN' }, response => {
            if (chrome.runtime.lastError || !response?.success) {
                const error = response?.error || chrome.runtime.lastError?.message || 'DAILY_CHECK_IN_FAILED';
                checkInBtn.disabled = false;
                if (label) label.textContent = defaultText;

                const message = error === 'SEARCH_RUNNING'
                    ? 'Dang search, hay dung truoc.'
                    : error === 'READ_TO_EARN_RUNNING'
                        ? 'Read to Earn dang chay.'
                        : error === 'DAILY_CHECK_IN_RUNNING'
                            ? 'Check In dang chay.'
                            : 'Khong chay duoc Check In: ' + error;
                showCheckInToast(message, 'error');
            }
        });
    });
});

document.addEventListener('DOMContentLoaded', () => {
    const checkInButtons = Array.from(document.querySelectorAll('[data-checkin]'));
    const readEarnButtons = Array.from(document.querySelectorAll('[data-read-earn]'));
    if (!checkInButtons.length && !readEarnButtons.length) return;

    function showAutoTaskToast(message, type = 'success') {
        const currentToast = document.querySelector('.toast');
        if (currentToast) currentToast.remove();

        const toast = document.createElement('div');
        toast.className = 'toast ' + type;
        toast.textContent = message;
        document.body.appendChild(toast);

        requestAnimationFrame(() => toast.classList.add('show'));
        setTimeout(() => {
            toast.classList.remove('show');
            setTimeout(() => toast.remove(), 300);
        }, 1800);
    }

    function setGroup(buttons, value, key, save = false) {
        buttons.forEach(button => {
            button.classList.toggle('active', button.dataset[key] === value);
        });

        if (save) {
            const settings = {};
            if (key === 'checkin') settings.autoDailyCheckIn = value === 'on';
            if (key === 'readEarn') settings.autoReadToEarn = value === 'on';
            chrome.runtime.sendMessage({
                type: 'UPDATE_SETTINGS',
                settings
            });
        }
    }

    function setFromSettings(settings) {
        if (!settings) return;
        setGroup(checkInButtons, settings.autoDailyCheckIn ? 'on' : 'off', 'checkin');
        setGroup(readEarnButtons, settings.autoReadToEarn ? 'on' : 'off', 'readEarn');
    }

    checkInButtons.forEach(button => {
        button.addEventListener('click', () => {
            const value = button.dataset.checkin;
            setGroup(checkInButtons, value, 'checkin', true);
            showAutoTaskToast(value === 'on' ? 'Check In: Auto sau khi search' : 'Check In: Chạy thủ công');
        });
    });

    readEarnButtons.forEach(button => {
        button.addEventListener('click', () => {
            const value = button.dataset.readEarn;
            setGroup(readEarnButtons, value, 'readEarn', true);
            showAutoTaskToast(value === 'on' ? 'Read to Earn: Auto sau Check In' : 'Read to Earn: Chạy thủ công');
        });
    });

    chrome.runtime.sendMessage({ type: 'GET_STATUS' }, response => {
        setFromSettings(response?.settings);
    });

    chrome.runtime.onMessage.addListener(message => {
        if (message?.type === 'STATUS_UPDATE') {
            setFromSettings(message.data?.settings);
            const disabled = !!message.data?.isRunning;
            [...checkInButtons, ...readEarnButtons].forEach(button => {
                button.disabled = disabled;
            });
        }
    });
});

document.addEventListener('DOMContentLoaded', () => {
    const minInput = document.getElementById('readToEarnDelayMin');
    const maxInput = document.getElementById('readToEarnDelayMax');
    const minDown = document.getElementById('readToEarnDelayMinDown');
    const minUp = document.getElementById('readToEarnDelayMinUp');
    const maxDown = document.getElementById('readToEarnDelayMaxDown');
    const maxUp = document.getElementById('readToEarnDelayMaxUp');
    const controls = [minInput, maxInput, minDown, minUp, maxDown, maxUp].filter(Boolean);

    if (!minInput || !maxInput) return;

    function clamp(value, min, max) {
        return Math.min(Math.max(value, min), max);
    }

    function normalize() {
        const minLimit = parseInt(minInput.min, 10) || 5;
        const maxLimit = parseInt(maxInput.max, 10) || 300;
        let minValue = clamp(parseInt(minInput.value, 10) || 30, minLimit, maxLimit);
        let maxValue = clamp(parseInt(maxInput.value, 10) || 60, minLimit, maxLimit);

        if (minValue > maxValue) maxValue = minValue;

        minInput.value = String(minValue);
        maxInput.value = String(maxValue);

        return {
            readToEarnDelayMin: minValue * 1000,
            readToEarnDelayMax: maxValue * 1000
        };
    }

    function saveReadToEarnDelay() {
        chrome.runtime.sendMessage({
            type: 'UPDATE_SETTINGS',
            settings: normalize()
        });
    }

    function setFromSettings(settings) {
        if (!settings) return;
        if (document.activeElement === minInput || document.activeElement === maxInput) return;

        minInput.value = String(Math.round((settings.readToEarnDelayMin || 30000) / 1000));
        maxInput.value = String(Math.round((settings.readToEarnDelayMax || 60000) / 1000));
        normalize();
    }

    function step(input, amount) {
        input.value = String((parseInt(input.value, 10) || 0) + amount);
        saveReadToEarnDelay();
    }

    minDown?.addEventListener('click', () => step(minInput, -1));
    minUp?.addEventListener('click', () => step(minInput, 1));
    maxDown?.addEventListener('click', () => step(maxInput, -1));
    maxUp?.addEventListener('click', () => step(maxInput, 1));
    minInput.addEventListener('input', saveReadToEarnDelay);
    maxInput.addEventListener('input', saveReadToEarnDelay);

    chrome.runtime.sendMessage({ type: 'GET_STATUS' }, response => {
        setFromSettings(response?.settings);
    });

    chrome.runtime.onMessage.addListener(message => {
        if (message?.type === 'STATUS_UPDATE') {
            setFromSettings(message.data?.settings);
            controls.forEach(control => {
                control.disabled = !!message.data?.isRunning;
            });
        } else if (message?.type === 'READ_TO_EARN_STATUS') {
            controls.forEach(control => {
                control.disabled = !!message.data?.isRunning;
            });
        }
    });
});
